   724→func (s *sharedIndexInformer) HandleDeltas(obj interface{}, isInInitialList bool) error {
   725→	s.blockDeltas.Lock()
   726→	defer s.blockDeltas.Unlock()
   727→
   728→	if deltas, ok := obj.(Deltas); ok {
   729→		return processDeltas(s, s.indexer, deltas, isInInitialList, s.keyFunc)
   730→	}
