   748→// Conforms to ResourceEventHandler
   749→func (s *sharedIndexInformer) OnUpdate(old, new interface{}) {
   750→	isSync := false
   751→
   752→	// If is a Sync event, isSync should be true
   753→	// If is a Replaced event, isSync is true if resource version is unchanged.
   754→	// If RV is unchanged: this is a Sync/Replaced event, so isSync is true
   755→
   756→	if accessor, err := meta.Accessor(new); err == nil {
   757→		if oldAccessor, err := meta.Accessor(old); err == nil {
   758→			// Events that didn't change resourceVersion are treated as resync events
   759→			// and only propagated to listeners that requested resync
   760→			isSync = accessor.GetResourceVersion() == oldAccessor.GetResourceVersion()
   761→		}
   762→	}
   763→
   764→	// Invocation of this function is locked under s.blockDeltas, so it is
   765→	// safe to distribute the notification
   766→	s.cacheMutationDetector.AddObject(new)
   767→	s.processor.distribute(updateNotification{oldObj: old, newObj: new}, isSync)
   768→}
